import{_ as o,o as t,c as n,ag as p}from"./chunks/framework.CAXxHpAX.js";const v=JSON.parse('{"title":"春秋：老子，道家学派创始人。无为而治，顺","description":"","frontmatter":{},"headers":[],"relativePath":"notes/note-2.md","filePath":"notes/note-2.md"}'),e={name:"notes/note-2.md"};function r(s,a,l,c,d,i){return t(),n("div",null,[...a[0]||(a[0]=[p('<h1 id="春秋-老子-道家学派创始人。无为而治-顺" tabindex="-1">春秋：老子，道家学派创始人。无为而治，顺 <a class="header-anchor" href="#春秋-老子-道家学派创始人。无为而治-顺" aria-label="Permalink to &quot;春秋：老子，道家学派创始人。无为而治，顺&quot;">​</a></h1><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">1、春秋：</span>老子，道家学派创始人。无为而治，顺应自然，事物都有对立面，可以相互转化。</p><p>孔子，儒家学派创始人。仁，仁者爱人。以德治国。创办私学，有教无类。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">2、百家争鸣：</span>战国： 墨家：兼爱非攻尚贤节俭</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">儒家：</span>孟子，仁政，民贵君轻，反对一切非正义战争</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">儒家：</span>荀子，礼治</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">道家：</span>庄子，顺应自然和民心，精神自由，人格独立</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">法家：</span>韩非，以法治国，树立君主权威，建立中央集权专制统治。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">3、百家争鸣的影响：</span>促进了思想和学术的繁荣，成为中国古代第一次思想文化发展的高峰。为中国古代文化的发展奠定了基础，对后世有十分重要的影响。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">4、江南地区开发的根本原因：</span>北人南迁带来了劳动力、技术、工具</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">5、魏晋时期，北方民族交融的表现：</span>胡汉观念淡薄，民族偏见和隔阂减少</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">6、首都：</span>秦：咸阳 西汉：长安 东汉：洛阳</p><p>7、第一次人口迁徙高潮的事件？西晋八王之乱</p>',13)])])}const _=o(e,[["render",r]]);export{v as __pageData,_ as default};
